import{_ as r,o as i,c as d,a2 as a}from"./chunks/framework.Cuq8tsM6.js";const v=JSON.parse('{"title":"Co-Branded Contest (publisher)","description":"","frontmatter":{"title":"Co-Branded Contest (publisher)"},"headers":[],"relativePath":"docs/fr/publishers/co-branded-contest/index.md","filePath":"docs/fr/publishers/co-branded-contest/index.md"}'),t={name:"docs/fr/publishers/co-branded-contest/index.md"};function s(o,e,n,p,u,c){return i(),d("div",null,[...e[0]||(e[0]=[a('<h1 id="jeu-concours-co-brande" tabindex="-1">Jeu Concours Co-brandé <a class="header-anchor" href="#jeu-concours-co-brande" aria-label="Permalink to &quot;Jeu Concours Co-brandé&quot;">​</a></h1><p>Animez votre communauté tout en monétisant votre audience grâce à des opérations financées par les marques.</p><div><a href="setup-guide" class="btn btn-primary">Guide de mise en place</a></div><hr><h2>Pourquoi proposer ce format ?</h2><div style="display:grid;grid-template-columns:repeat(auto-fit, minmax(280px, 1fr));gap:20px;width:100%;margin-bottom:40px;"><div style="border:1px solid var(--vp-c-divider);border-radius:8px;padding:24px;background:var(--vp-c-bg-elv);"><h3>💰 Revenus Média</h3><p>L&#39;Annonceur finance tout (dotations + coûts). C&#39;est une source de revenus additionnelle sans risque.</p></div><div style="border:1px solid var(--vp-c-divider);border-radius:8px;padding:24px;background:var(--vp-c-bg-elv);"><h3>🎉 Animation Commerciale</h3><p>Offrez une expérience ludique et des cadeaux attractifs à vos clients. Cela dynamise votre site et vos newsletters.</p></div><div style="border:1px solid var(--vp-c-divider);border-radius:8px;padding:24px;background:var(--vp-c-bg-elv);"><h3>📊 Qualification Data</h3><p>Profitez du jeu pour réactiver des clients inactifs ou collecter de nouveaux opt-ins sur votre propre base.</p></div></div><h2>Le Concept</h2><div style="background:var(--gi-tint-blue-bg);padding:24px;border-radius:8px;border-left:4px solid var(--gi-accent);margin-bottom:40px;"><p> Vous hébergez une <strong>page de jeu sur votre site</strong> (ou une page dédiée externe).<br> Vous dirigez du trafic dessus via vos canaux habituels (Email, Push, Social).<br> L&#39;Annonceur récupère les leads &quot;Opt-in&quot; à la fin de l&#39;opération. </p></div><h2>Pourquoi passer par getinside ?</h2><div style="display:flex;flex-direction:column;gap:20px;"><div style="border:1px solid var(--vp-c-divider);border-radius:8px;padding:24px;background:var(--vp-c-bg-elv);display:flex;align-items:center;gap:20px;"><div style="font-size:32px;min-width:50px;text-align:center;">⚖️</div><div><h3>Sécurité Juridique</h3><p>La collecte de data partagée est complexe (RGPD). Nous fournissons les modèles de mentions légales et de cases à cocher validés par des juristes.</p></div></div><div style="border:1px solid var(--vp-c-divider);border-radius:8px;padding:24px;background:var(--vp-c-bg-elv);display:flex;align-items:center;gap:20px;"><div style="font-size:32px;min-width:50px;text-align:center;">🤝</div><div><h3>Gestion des Dotations</h3><p>Vous ne gérez pas l&#39;envoi des lots aux gagnants. C&#39;est l&#39;Annonceur qui s&#39;en charge. Votre responsabilité s&#39;arrête à l&#39;hébergement du jeu.</p></div></div></div>',10)])])}const x=r(t,[["render",s]]);export{v as __pageData,x as default};
